import{_ as e}from"./chunks/floatingball.D-BT0bmL.js";import{_ as a,a as o}from"./chunks/sidebar-chat-messages.symtOcQN.js";import{_ as i,o as n,c as r,ag as s}from"./chunks/framework.BqfgOMAh.js";const w=JSON.parse('{"title":"AI Chat","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/ai-chat.md","filePath":"en/guide/ai-chat.md"}'),l={name:"en/guide/ai-chat.md"};function h(d,t,c,u,p,g){return n(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="ai-chat" tabindex="-1">AI Chat <a class="header-anchor" href="#ai-chat" aria-label="Permalink to &quot;AI Chat&quot;">​</a></h1><p>The core NexusFlow experience revolves around using AI chat to operate Unreal Engine Blueprints. This page covers every part of the chat interface and how to use it.</p><h2 id="floating-ball" tabindex="-1">Floating Ball <a class="header-anchor" href="#floating-ball" aria-label="Permalink to &quot;Floating Ball&quot;">​</a></h2><p><img src="'+e+'" alt="NexusFlow floating ball"></p><p>The floating ball is NexusFlow&#39;s quick-access entry point on your desktop, always visible on top of other windows.</p><ul><li><strong>Appearance</strong>: A circular button — blue-purple gradient when UE is connected, gray when disconnected — with a Nexus network pattern logo. A small red dot appears at the bottom-right when UE is not connected</li><li><strong>Click</strong>: Opens or switches to the AI chat sidebar</li><li><strong>Drag</strong>: Hold and drag to reposition; the ball automatically snaps to the nearest screen edge when released</li><li><strong>Close</strong>: Hover to reveal a close button (×) in the top-right corner; clicking it shows a confirmation dialog</li><li><strong>Hide</strong>: You can hide the floating ball entirely and restore it from the system tray icon</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>A movement of more than 5 pixels is treated as a drag. Short touches will still trigger a click to open the sidebar.</p></div><h2 id="sidebar-interface" tabindex="-1">Sidebar Interface <a class="header-anchor" href="#sidebar-interface" aria-label="Permalink to &quot;Sidebar Interface&quot;">​</a></h2><p><img src="'+a+'" alt="AI chat sidebar - empty state"></p><p>The sidebar is the main AI chat interface, divided into three areas:</p><h3 id="top-header" tabindex="-1">Top Header <a class="header-anchor" href="#top-header" aria-label="Permalink to &quot;Top Header&quot;">​</a></h3><p>The header area contains the following controls:</p><table tabindex="0"><thead><tr><th>Element</th><th>Description</th></tr></thead><tbody><tr><td><strong>Logo + Title</strong></td><td>Displays &quot;NexusFlow AI&quot;; appends the project name when connected to UE</td></tr><tr><td><strong>New Chat</strong></td><td>Start a new conversation (shows a confirmation dialog)</td></tr><tr><td><strong>Mode Switch</strong></td><td>Toggle window mode (Floating / Dock Left / Dock Right)</td></tr><tr><td><strong>Quick Action</strong></td><td>Pin-to-top button in floating mode; switch-direction button in docked mode</td></tr><tr><td><strong>Settings</strong></td><td>Gear icon — opens the Settings page</td></tr><tr><td><strong>Close</strong></td><td>Hides the sidebar</td></tr></tbody></table><p>In floating mode, you can hold and drag the header area to move the entire window.</p><h3 id="chat-area" tabindex="-1">Chat Area <a class="header-anchor" href="#chat-area" aria-label="Permalink to &quot;Chat Area&quot;">​</a></h3><p><img src="'+o+'" alt="AI chat sidebar with messages"></p><p>The main content area is where you interact with the AI:</p><ul><li><strong>Message Display</strong>: Shows the conversation history between you and the AI</li><li><strong>Initial Message</strong>: On first open, the AI sends a multilingual self-introduction (based on your Agent response language setting)</li><li><strong>Tool Calls</strong>: When the AI performs Blueprint operations, you can see tool call status in real time</li><li><strong>Stop Generation</strong>: Click the stop button to interrupt the AI&#39;s response</li></ul><div class="warning custom-block"><p class="custom-block-title">Note</p><p>When the AI is actively executing a tool operation (e.g., modifying a Blueprint), it cannot be interrupted. Clicking stop at that point will show a toast message: &quot;Tool is executing, cannot interrupt.&quot;</p></div><h3 id="bottom-status-bar" tabindex="-1">Bottom Status Bar <a class="header-anchor" href="#bottom-status-bar" aria-label="Permalink to &quot;Bottom Status Bar&quot;">​</a></h3><p>The status bar displays connection status and current model information:</p><ul><li><strong>Connection Status</strong>: 🟢 Green dot means UE is connected (shows project name and UE version); 🔴 Red dot means disconnected</li><li><strong>Current Model</strong>: The right side shows the name of the currently active AI model</li><li><strong>Status Messages</strong>: Operational feedback (e.g., compilation results) appears as a temporary banner</li></ul><h2 id="window-modes" tabindex="-1">Window Modes <a class="header-anchor" href="#window-modes" aria-label="Permalink to &quot;Window Modes&quot;">​</a></h2><p>The sidebar supports three window modes, selectable from the mode switch menu in the header:</p><h3 id="floating-window-default" tabindex="-1">Floating Window (Default) <a class="header-anchor" href="#floating-window-default" aria-label="Permalink to &quot;Floating Window (Default)&quot;">​</a></h3><p>An independent window that you can freely move and resize:</p><ul><li>Drag the header to reposition the window</li><li>Use the pin button to keep the window always on top</li><li>Best for scenarios where you need to view the UE Editor at the same time</li></ul><h3 id="dock-left-dock-right" tabindex="-1">Dock Left / Dock Right <a class="header-anchor" href="#dock-left-dock-right" aria-label="Permalink to &quot;Dock Left / Dock Right&quot;">​</a></h3><p>The sidebar automatically attaches to the edge of the screen, similar to a VS Code sidebar:</p><ul><li>Occupies the full height of the screen on one side</li><li>Drag the edge to adjust width</li><li>A quick-action button lets you switch to the opposite side with one click</li><li>Best for extended chat sessions</li></ul><div class="tip custom-block"><p class="custom-block-title">Quick Switch</p><p>In docked mode, the arrow button in the header quickly moves the sidebar to the other side of the screen.</p></div><h2 id="chat-capabilities" tabindex="-1">Chat Capabilities <a class="header-anchor" href="#chat-capabilities" aria-label="Permalink to &quot;Chat Capabilities&quot;">​</a></h2><h3 id="natural-language-operations" tabindex="-1">Natural Language Operations <a class="header-anchor" href="#natural-language-operations" aria-label="Permalink to &quot;Natural Language Operations&quot;">​</a></h3><p>Describe your needs in plain language, and the AI will automatically:</p><ul><li>Read the current Blueprint&#39;s structure and node information</li><li>Modify the Blueprint as needed (add/remove/update nodes and connections)</li><li>Create new Blueprint logic</li><li>Manage variables, functions, and events</li></ul><h3 id="automatic-ue-context-sync" tabindex="-1">Automatic UE Context Sync <a class="header-anchor" href="#automatic-ue-context-sync" aria-label="Permalink to &quot;Automatic UE Context Sync&quot;">​</a></h3><p>NexusFlow automatically syncs UE Editor context to the AI, including:</p><ul><li>Connection status and UE version</li><li>Current project name</li><li>Currently open Blueprint information</li><li>Selected nodes and Actors</li><li>Edit mode and active window</li></ul><p>This means you don&#39;t need to manually tell the AI which Blueprint you&#39;re editing — it already knows.</p><h3 id="tool-call-tracking" tabindex="-1">Tool Call Tracking <a class="header-anchor" href="#tool-call-tracking" aria-label="Permalink to &quot;Tool Call Tracking&quot;">​</a></h3><p>When the AI needs to perform Blueprint operations, it calls the appropriate tools. In the chat, you&#39;ll see:</p><ul><li>Tool name and parameters</li><li>Execution status (in progress / succeeded / failed)</li><li>Result summary</li></ul><h3 id="new-chat" tabindex="-1">New Chat <a class="header-anchor" href="#new-chat" aria-label="Permalink to &quot;New Chat&quot;">​</a></h3><p>Click the New Chat button in the header to start a fresh conversation. Since the current version does not support chat history, starting a new chat clears the current conversation, so a confirmation dialog appears.</p><h3 id="stop-generation" tabindex="-1">Stop Generation <a class="header-anchor" href="#stop-generation" aria-label="Permalink to &quot;Stop Generation&quot;">​</a></h3><p>While the AI is generating a response, click the stop button to interrupt it. Keep in mind:</p><ul><li>✅ Can stop: While the AI is generating a text reply</li><li>❌ Cannot stop: While the AI is executing a tool operation (e.g., modifying a Blueprint)</li></ul><h2 id="system-tray" tabindex="-1">System Tray <a class="header-anchor" href="#system-tray" aria-label="Permalink to &quot;System Tray&quot;">​</a></h2><p>NexusFlow places a persistent icon in the Windows system tray (the area on the right side of the taskbar).</p><ul><li><strong>Restore Floating Ball</strong>: If you&#39;ve hidden the floating ball, right-click the tray icon to restore it</li><li><strong>Quick Access</strong>: Click the tray icon to quickly open the sidebar</li></ul><div class="tip custom-block"><p class="custom-block-title">Finding the System Tray</p><p>If you can&#39;t see the NexusFlow icon, click the up arrow (∧) on the taskbar to reveal hidden icons.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./quick-menu">UE Quick Menu</a> — 17 AI operations across 4 entry points in the UE Editor</li><li><a href="./blueprint-operations">Blueprint Operations</a> — Detailed Blueprint operation examples and tips</li><li><a href="./settings">Settings</a> — Customize window modes, hotkeys, and more</li></ul>',53)])])}const k=i(l,[["render",h]]);export{w as __pageData,k as default};
